import React, { useState, useRef, useEffect } from 'react';
import Header from './components/Header';
import SgpaCalculator from './components/SgpaCalculator';
import CgpaCalculator from './components/CgpaCalculator';
import ImprovementCalculator from './components/ImprovementCalculator';
import ConfirmationModal from './components/ConfirmationModal';
import ElectricIcon from './components/icons/ElectricIcon';
import TrendingUpIcon from './components/icons/TrendingUpIcon';
import TrashIcon from './components/icons/TrashIcon';
import LinkedInIcon from './components/icons/LinkedInIcon';

type View = 'sgpa' | 'cgpa' | 'improvement';

interface SgpaState {
  selectedSemesterKey: string;
  grades: Record<string, string>;
}

interface CgpaState {
  gpas: Record<string, string>;
}

export interface ImprovementState {
  selectedSemesterKey: string;
  semesterData: Record<string, {
    currentGpa: string;
    selectedCourses: Record<string, string>;
  }>;
}

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<View>('sgpa');
  const [isModalOpen, setIsModalOpen] = useState(false);

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    const savedTheme = localStorage.getItem('theme');
    const userPrefersDark = window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches;
    if (savedTheme === 'dark' || (!savedTheme && userPrefersDark)) {
      return 'dark';
    }
    return 'light';
  });

  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [theme]);

  const handleThemeToggle = () => {
    setTheme(prevTheme => (prevTheme === 'light' ? 'dark' : 'light'));
  };

  const [sgpaState, setSgpaState] = useState<SgpaState>(() => {
    try {
      const saved = localStorage.getItem('sgpaState');
      if (saved) {
        return JSON.parse(saved);
      }
    } catch (error) {
      console.error('Error reading sgpaState from localStorage', error);
    }
    return { selectedSemesterKey: '', grades: {} };
  });

  const [cgpaState, setCgpaState] = useState<CgpaState>(() => {
    try {
      const saved = localStorage.getItem('cgpaState');
      if (saved) {
        return JSON.parse(saved);
      }
    } catch (error) {
      console.error('Error reading cgpaState from localStorage', error);
    }
    return { gpas: {} };
  });

  const [improvementState, setImprovementState] = useState<ImprovementState>(() => {
    try {
      const saved = localStorage.getItem('improvementState');
      if (saved) {
        return JSON.parse(saved);
      }
    } catch (error) {
      console.error('Error reading improvementState from localStorage', error);
    }
    return { selectedSemesterKey: '', semesterData: {} };
  });

  useEffect(() => {
    try {
      localStorage.setItem('sgpaState', JSON.stringify(sgpaState));
    } catch (error) {
      console.error('Error saving sgpaState to localStorage', error);
    }
  }, [sgpaState]);

  useEffect(() => {
    try {
      localStorage.setItem('cgpaState', JSON.stringify(cgpaState));
    } catch (error) {
      console.error('Error saving cgpaState to localStorage', error);
    }
  }, [cgpaState]);

  useEffect(() => {
    try {
      localStorage.setItem('improvementState', JSON.stringify(improvementState));
    } catch (error) {
      console.error('Error saving improvementState to localStorage', error);
    }
  }, [improvementState]);

  const sgpaButtonRef = useRef<HTMLButtonElement>(null);
  const cgpaButtonRef = useRef<HTMLButtonElement>(null);
  const improvementButtonRef = useRef<HTMLButtonElement>(null);
  const [gliderStyle, setGliderStyle] = useState({});

  useEffect(() => {
    const updateGlider = () => {
        let targetButton: HTMLButtonElement | null = null;

        if (activeView === 'sgpa') targetButton = sgpaButtonRef.current;
        else if (activeView === 'cgpa') targetButton = cgpaButtonRef.current;
        else if (activeView === 'improvement') targetButton = improvementButtonRef.current;

        if (targetButton) {
        setGliderStyle({
            width: `${targetButton.offsetWidth}px`,
            transform: `translateX(${targetButton.offsetLeft}px)`,
        });
        }
    };

    // Initial update
    updateGlider();

    // Update on resize to handle orientation changes on mobile
    window.addEventListener('resize', updateGlider);

    // Cleanup
    return () => window.removeEventListener('resize', updateGlider);
  }, [activeView]);

  const handleClearAllData = () => {
    setSgpaState({ selectedSemesterKey: '', grades: {} });
    setCgpaState({ gpas: {} });
    setImprovementState({ selectedSemesterKey: '', semesterData: {} });
    setIsModalOpen(false);
  };

  return (
    <div className="min-h-screen text-neutral-800 dark:text-neutral-200 relative isolate flex flex-col">
      <div className="fixed top-0 left-0 -z-10 h-full w-full bg-neutral-50 dark:bg-neutral-950">
        <div className="absolute top-0 left-0 h-[500px] w-[500px] sm:h-[700px] sm:w-[700px] animate-[blob-spin_30s_linear_infinite] rounded-full bg-gradient-to-br from-purple-500/20 to-pink-500/20 blur-3xl opacity-50 dark:opacity-30"></div>
        <div className="absolute bottom-0 right-0 h-[500px] w-[500px] sm:h-[700px] sm:w-[700px] animate-[blob-spin-reverse_35s_linear_infinite] rounded-full bg-gradient-to-tl from-indigo-500/20 to-sky-500/20 blur-3xl opacity-50 dark:opacity-30"></div>
      </div>

      <Header theme={theme} onToggleTheme={handleThemeToggle} />
      <main className="container mx-auto px-4 py-4 sm:py-10 flex-grow">

        {/* Department Title - Moved here and styled for better visibility and mobile alignment */}
        <div className="text-center mb-8 px-4">
            <h3 className="flex flex-col sm:flex-row items-center justify-center gap-2 sm:gap-3 text-lg sm:text-xl font-extrabold tracking-tight text-neutral-900 dark:text-white">
                <ElectricIcon className="w-6 h-6 sm:w-7 sm:h-7 text-yellow-500 dark:text-yellow-400 flex-shrink-0" />
                <span className="leading-snug">Department of Electrical and Electronic Engineering, GSTU</span>
            </h3>
        </div>

        <div className="flex justify-center mb-6 sm:mb-8">
          <div className="relative grid grid-cols-3 sm:flex p-1 bg-black/5 dark:bg-white/5 backdrop-blur-md rounded-xl shadow-inner border border-white/30 dark:border-black/30 w-full sm:w-auto" role="tablist">
            <span 
                className="absolute top-1 bottom-1 transition-all duration-300 ease-[cubic-bezier(0.25,1,0.5,1)] bg-gradient-to-br from-white/80 to-white/60 dark:from-neutral-800/90 dark:to-neutral-800/70 backdrop-blur-sm rounded-lg shadow-md border border-white dark:border-white/10"
                style={gliderStyle}
                aria-hidden="true"
            ></span>

            <button 
                ref={sgpaButtonRef}
                onClick={() => setActiveView('sgpa')}
                className={`relative z-10 flex items-center justify-center px-1 sm:px-5 py-2.5 sm:py-2 text-xs sm:text-base font-semibold whitespace-nowrap rounded-lg focus:outline-none focus-visible:ring-2 focus-visible:ring-primary-500/75 transition-colors duration-300 ${activeView === 'sgpa' ? 'text-neutral-900 dark:text-white' : 'text-neutral-600 dark:text-neutral-400 hover:text-neutral-900 dark:hover:text-white'}`}
                role="tab"
                aria-selected={activeView === 'sgpa'}
                aria-controls="sgpa-panel"
            >
                GPA Calculator
            </button>
            <button 
                ref={cgpaButtonRef}
                onClick={() => setActiveView('cgpa')}
                className={`relative z-10 flex items-center justify-center px-1 sm:px-5 py-2.5 sm:py-2 text-xs sm:text-base font-semibold whitespace-nowrap rounded-lg focus:outline-none focus-visible:ring-2 focus-visible:ring-primary-500/75 transition-colors duration-300 ${activeView === 'cgpa' ? 'text-neutral-900 dark:text-white' : 'text-neutral-600 dark:text-neutral-400 hover:text-neutral-900 dark:hover:text-white'}`}
                role="tab"
                aria-selected={activeView === 'cgpa'}
                aria-controls="cgpa-panel"
            >
                CGPA Calculator
            </button>
            <button 
                ref={improvementButtonRef}
                onClick={() => setActiveView('improvement')}
                className={`relative z-10 flex items-center justify-center px-1 sm:px-5 py-2.5 sm:py-2 text-xs sm:text-base font-semibold whitespace-nowrap rounded-lg gap-1 sm:gap-2 focus:outline-none focus-visible:ring-2 focus-visible:ring-primary-500/75 transition-colors duration-300 ${activeView === 'improvement' ? 'text-neutral-900 dark:text-white' : 'text-neutral-600 dark:text-neutral-400 hover:text-neutral-900 dark:hover:text-white'}`}
                role="tab"
                aria-selected={activeView === 'improvement'}
                aria-controls="improvement-panel"
            >
                <TrendingUpIcon className="w-3.5 h-3.5 sm:w-4 sm:h-4" />
                Retake GPA
            </button>
          </div>
        </div>

        <div role="tabpanel" id="sgpa-panel" hidden={activeView !== 'sgpa'}>
          {activeView === 'sgpa' && <SgpaCalculator sgpaState={sgpaState} setSgpaState={setSgpaState} />}
        </div>
        <div role="tabpanel" id="cgpa-panel" hidden={activeView !== 'cgpa'}>
          {activeView === 'cgpa' && <CgpaCalculator cgpaState={cgpaState} setCgpaState={setCgpaState} />}
        </div>
        <div role="tabpanel" id="improvement-panel" hidden={activeView !== 'improvement'}>
          {activeView === 'improvement' && <ImprovementCalculator improvementState={improvementState} setImprovementState={setImprovementState} />}
        </div>

        <div className="flex justify-center mt-8 mb-4">
            <button
                onClick={() => setIsModalOpen(true)}
                className="group flex items-center justify-center gap-2 px-8 py-3 bg-white/50 dark:bg-red-900/10 hover:bg-red-50 dark:hover:bg-red-900/20 text-red-600 dark:text-red-400 font-bold rounded-xl border border-red-200 dark:border-red-800/50 backdrop-blur-sm transition-all duration-200 shadow-sm hover:shadow-md hover:scale-[1.02] active:scale-[0.98]"
            >
                <TrashIcon className="w-5 h-5 group-hover:rotate-12 transition-transform duration-300" />
                Clear All Data
            </button>
        </div>
      </main>

      <footer className="mt-auto w-full border-t border-neutral-200/60 dark:border-neutral-800/60 bg-white/40 dark:bg-black/20 backdrop-blur-xl py-6 relative z-10">
        <div className="container mx-auto px-4 flex flex-col md:flex-row items-center justify-between gap-4">
            <div className="flex flex-col items-center md:items-start gap-1">
                <p className="text-sm text-neutral-600 dark:text-neutral-400 font-medium text-center md:text-left flex items-center gap-1.5 flex-wrap justify-center">
                    Developed with passion by <span className="font-signature text-xl bg-gradient-to-r from-indigo-500 to-purple-500 bg-clip-text text-transparent font-bold pt-1">Introverted Sunax</span>
                </p>
                <div className="text-[10px] text-neutral-400 dark:text-neutral-500 uppercase tracking-widest font-bold opacity-80">
                   GSTU • EEE
                </div>
            </div>

            <a 
              href="https://linkedin.com/in/hossain-sumon"
              target="_blank"
              rel="noopener noreferrer" 
              className="group relative px-5 py-2.5 rounded-full bg-white/50 dark:bg-neutral-800/50 hover:bg-white/80 dark:hover:bg-neutral-800 backdrop-blur-sm border border-neutral-200/80 dark:border-neutral-700/80 shadow-sm hover:shadow-md transition-all duration-300 flex items-center gap-2.5"
            >
              <div className="text-neutral-400 group-hover:text-[#0A66C2] transition-colors duration-300">
                 <LinkedInIcon className="w-4 h-4" />
              </div>
              <span className="text-sm font-semibold text-neutral-600 dark:text-neutral-300 group-hover:text-neutral-900 dark:group-hover:text-white transition-colors duration-300">
                Message Me
              </span>
            </a>
        </div>
      </footer>

      <ConfirmationModal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onConfirm={handleClearAllData}
        title="Confirm Data Deletion"
      >
        Are you sure you want to clear all your saved SGPA and CGPA data? This action cannot be undone.
      </ConfirmationModal>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { SEMESTER_COURSES, GRADE_POINTS, GRADE_OPTIONS } from '../constants';
import { Course } from '../types';
import ImprovementDisplay from './ImprovementDisplay';
import TrashIcon from './icons/TrashIcon';

export interface ImprovementState {
  selectedSemesterKey: string;
  semesterData: Record<string, {
    currentGpa: string;
    selectedCourses: Record<string, string>;
  }>;
}

interface ImprovementCalculatorProps {
  improvementState: ImprovementState;
  setImprovementState: React.Dispatch<React.SetStateAction<ImprovementState>>;
}

const ImprovementCalculator: React.FC<ImprovementCalculatorProps> = ({ improvementState, setImprovementState }) => {
  const { selectedSemesterKey, semesterData } = improvementState;

  // Retrieve data specifically for the selected semester, or default to empty
  const currentSemesterData = useMemo(() => {
     return semesterData[selectedSemesterKey] || { currentGpa: '', selectedCourses: {} as Record<string, string> };
  }, [semesterData, selectedSemesterKey]);

  const { currentGpa, selectedCourses } = currentSemesterData;

  // Sticky header state
  const [isSticky, setIsSticky] = useState(false);
  const [isMounted, setIsMounted] = useState(false);
  const displayElementRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setIsMounted(true);
    const displayElement = displayElementRef.current;
    if (!displayElement) return;

    const observer = new IntersectionObserver(
        ([entry]) => {
            setIsSticky(!entry.isIntersecting && entry.boundingClientRect.y < 0);
        },
        { rootMargin: '-1px 0px 0px 0px', threshold: 1 }
    );

    observer.observe(displayElement);

    return () => {
        if (displayElement) observer.unobserve(displayElement);
    };
  }, []);

  const courses: Course[] = useMemo(
    () => (selectedSemesterKey ? SEMESTER_COURSES[selectedSemesterKey] : []),
    [selectedSemesterKey]
  );

  const availableCourses = useMemo(() => {
    return courses.filter(course => !selectedCourses[course.code]);
  }, [courses, selectedCourses]);

  const totalSemesterCredits = useMemo(() => {
    return courses.reduce((sum, course) => sum + course.credits, 0);
  }, [courses]);

  const calculationResult = useMemo(() => {
    const currentGpaNum = parseFloat(currentGpa);

    // 1. Calculate current secured point
    let currentSecuredPoints = 0;
    if (!isNaN(currentGpaNum) && totalSemesterCredits > 0) {
      currentSecuredPoints = currentGpaNum * totalSemesterCredits;
    }

    // 2. Calculate point of improved courses
    let improvedCoursePoints = 0;
    let improvedCreditsCount = 0;

    Object.entries(selectedCourses).forEach(([courseCode, grade]) => {
      const course = courses.find(c => c.code === courseCode);
      const gradePoint = GRADE_POINTS[grade as string];

      if (course && gradePoint !== undefined) {
        improvedCoursePoints += course.credits * gradePoint;
        improvedCreditsCount += course.credits;
      }
    });

    // 3. Update secured point
    const updatedSecuredPoints = currentSecuredPoints + improvedCoursePoints;

    // 4. Compute final updated CGPA
    const updatedGpa = totalSemesterCredits > 0 ? updatedSecuredPoints / totalSemesterCredits : 0;

    return {
      currentSecuredPoints,
      improvedCoursePoints,
      updatedSecuredPoints,
      updatedGpa,
      improvedCreditsCount
    };
  }, [currentGpa, totalSemesterCredits, selectedCourses, courses]);

  // Helper to safely update the current semester's data
  const updateCurrentSemesterData = (updates: Partial<{ currentGpa: string; selectedCourses: Record<string, string> }>) => {
    setImprovementState(prev => ({
      ...prev,
      semesterData: {
        ...prev.semesterData,
        [selectedSemesterKey]: {
          ...(prev.semesterData[selectedSemesterKey] || { currentGpa: '', selectedCourses: {} }),
          ...updates
        }
      }
    }));
  };

  const handleSemesterChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setImprovementState(prev => ({
      ...prev,
      selectedSemesterKey: e.target.value
    }));
  };

  const handleAddCourse = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const courseCode = e.target.value;
    if (courseCode) {
      updateCurrentSemesterData({
        selectedCourses: {
          ...selectedCourses,
          [courseCode]: 'N/A' // Default grade
        }
      });
    }
  };

  const handleRemoveCourse = (courseCode: string) => {
    const nextCourses = { ...selectedCourses };
    delete nextCourses[courseCode];
    updateCurrentSemesterData({ selectedCourses: nextCourses });
  };

  const handleGradeChange = (courseCode: string, grade: string) => {
    updateCurrentSemesterData({
      selectedCourses: {
        ...selectedCourses,
        [courseCode]: grade
      }
    });
  };

  const handleGpaChange = (val: string) => {
    updateCurrentSemesterData({ currentGpa: val });
  };

  const glassEffectClasses = "bg-gradient-to-br from-white/50 to-white/20 dark:from-neutral-900/50 dark:to-neutral-900/30 backdrop-blur-2xl border border-white/50 dark:border-white/10 shadow-xl shadow-black/10";
  const inputClasses = "w-full bg-white/20 dark:bg-black/20 backdrop-blur-sm border border-black/10 dark:border-white/10 shadow-inner rounded-xl py-3 px-4 text-base focus:ring-2 focus:ring-primary-500/80 focus:border-primary-500 outline-none transition";

  return (
    <section className={`transition-all duration-500 ease-out ${isMounted ? 'opacity-100 transform-none' : 'opacity-0 translate-y-4'}`}>

      {/* Display Section (Non-sticky) */}
      <div ref={displayElementRef} className="py-2 sm:py-4">
        <ImprovementDisplay 
            {...calculationResult}
            isSticky={false}
        />
      </div>

      {/* Sticky Header */}
      <div className={`fixed top-0 left-0 right-0 z-20 py-4 bg-neutral-50/80 dark:bg-neutral-950/80 backdrop-blur-lg border-b border-neutral-200/80 dark:border-neutral-800/80 transition-all duration-300 ease-in-out will-change-[transform,opacity] ${isSticky ? 'opacity-100 translate-y-0' : 'opacity-0 -translate-y-full pointer-events-none'}`}>
         <ImprovementDisplay 
            {...calculationResult}
            isSticky={true}
        />
      </div>

      <div className="max-w-3xl mx-auto mt-4 sm:mt-8">

        {/* Main Card */}
        <div className={`${glassEffectClasses} rounded-2xl p-4 sm:p-6`}>

          <div className="flex flex-col gap-4 mb-6">
             {/* Semester Selection */}
            <div className="space-y-1.5">
              <label className="block text-sm font-medium text-neutral-600 dark:text-neutral-400 ml-1">
                Select Semester
              </label>
              <select
                value={selectedSemesterKey}
                onChange={handleSemesterChange}
                className={inputClasses}
              >
                <option value="">Choose...</option>
                {Object.keys(SEMESTER_COURSES).map(key => (
                  <option key={key} value={key}>Semester {key}</option>
                ))}
              </select>
            </div>

            {/* Current GPA Input */}
            {selectedSemesterKey && (
                <div className="space-y-1.5 animate-in fade-in slide-in-from-left-2 duration-300">
                <label className="block text-sm font-medium text-neutral-600 dark:text-neutral-400 ml-1">
                    Current GPA
                </label>
                <input
                    type="number"
                    step="0.01"
                    min="0"
                    max="4"
                    value={currentGpa}
                    onChange={(e) => handleGpaChange(e.target.value)}
                    placeholder="e.g. 2.50"
                    inputMode="decimal"
                    className={inputClasses}
                />
                </div>
            )}
          </div>

          {selectedSemesterKey && (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
                {/* Divider */}
                <div className="h-px bg-black/10 dark:bg-white/10 my-6"></div>

                {/* Add Course */}
                <div className="mb-6 space-y-1.5">
                    <label className="block text-sm font-medium text-neutral-600 dark:text-neutral-400 ml-1">
                        Add Retake Course
                    </label>
                    <select 
                        onChange={handleAddCourse} 
                        value="" 
                        className={inputClasses}
                        disabled={availableCourses.length === 0}
                    >
                        <option value="" disabled>
                            {availableCourses.length === 0 ? "All courses added" : "Select Retake Course"}
                        </option>
                        {availableCourses.map(course => (
                            <option key={course.code} value={course.code}>
                                {course.name} ({course.code})
                            </option>
                        ))}
                    </select>
                </div>

                {/* Courses List */}
                <div className="space-y-3">
                    {Object.keys(selectedCourses).length === 0 && (
                        <div className="text-center py-8 border-2 border-dashed border-neutral-200/50 dark:border-neutral-800/50 rounded-xl">
                            <p className="text-neutral-500 dark:text-neutral-400 text-sm">No retake courses added yet.</p>
                            <p className="text-neutral-400 dark:text-neutral-500 text-xs mt-1">Select a course from the dropdown above to begin.</p>
                        </div>
                    )}

                    {Object.entries(selectedCourses).map(([courseCode, grade]) => {
                        const course = courses.find(c => c.code === courseCode);
                        if (!course) return null;

                        return (
                        <div 
                            key={course.code}
                            className="flex items-center justify-between p-4 rounded-2xl bg-slate-100 dark:bg-neutral-800/80 border border-slate-200 dark:border-neutral-700 shadow-sm"
                        >
                            <div className="flex-grow min-w-0 pr-4">
                                <h4 className="font-bold text-slate-800 dark:text-slate-100 text-base">{course.name}</h4>
                                <p className="text-sm text-slate-500 dark:text-slate-400 font-medium mt-1">{course.code} • {course.credits} Credits</p>
                            </div>

                            <div className="flex items-center gap-3">
                                <select
                                    value={grade}
                                    onChange={(e) => handleGradeChange(course.code, e.target.value)}
                                    className="h-10 w-20 bg-white dark:bg-neutral-900 border border-slate-200 dark:border-neutral-700 text-slate-800 dark:text-slate-200 text-base font-semibold rounded-lg focus:ring-2 focus:ring-indigo-500/50 focus:border-indigo-500 block px-2 outline-none shadow-sm transition-all"
                                >
                                    {GRADE_OPTIONS.map(opt => (
                                        <option key={opt} value={opt}>{opt}</option>
                                    ))}
                                </select>
                                <button 
                                    onClick={() => handleRemoveCourse(course.code)}
                                    className="p-2 text-slate-400 hover:text-red-500 dark:hover:text-red-400 transition-colors rounded-lg hover:bg-red-50 dark:hover:bg-red-900/20"
                                    title="Remove course"
                                >
                                    <TrashIcon className="w-5 h-5" />
                                </button>
                            </div>
                        </div>
                        );
                    })}
                </div>
            </div>
          )}
        </div>
      </div>
    </section>
  );
};

export default ImprovementCalculator;
